import{_ as p,o as e,c as t,d as o}from"./app.f44e8be6.js";const a={},n=o('<h1 id="\u57FA\u7840\u77E5\u8BC6" tabindex="-1"><a class="header-anchor" href="#\u57FA\u7840\u77E5\u8BC6" aria-hidden="true">#</a> \u57FA\u7840\u77E5\u8BC6</h1><p>\u8FDB\u7A0B\u7684\u7279\u6027\uFF1A\u5E76\u53D1\u6027\u3001\u52A8\u6001\u6027\u3001\u72EC\u7ACB\u6027\u3001\u4EA4\u5F80\u6027\u3001\u5F02\u6B65\u6027\u3001\u7ED3\u6784\u6027</p><p>\u64CD\u4F5C\u7CFB\u7EDF\u7684\u7279\u6027\uFF1A\u5E76\u53D1\u6027\u3001\u5171\u4EAB\u6027\u3001\u865A\u62DF\u6027\u3001\u968F\u673A\u6027</p><p>\u7528P\u3001V\u64CD\u4F5C\u7BA1\u7406\u4E92\u65A5\u4F7F\u7528\u7684\u8D44\u6E90\u65F6\uFF0C\u4FE1\u53F7\u91CF\u7684\u521D\u503C\u5E94\u5B9A\u4E49\u4E3A 1</p><p>P\u3001V\u64CD\u4F5C\u662F\u4E00\u7C7B\u4F4E\u7EA7\u901A\u4FE1\u539F\u8BED</p><p>\u7BA1\u7A0B\u5177\u6709\u4E09\u4E2A\u4E3B\u8981\u7684\u7279\u5F81\uFF1A\u6A21\u5757\u5316\u3001\u62BD\u8C61\u6570\u636E\u7C7B\u578B\u3001\u4FE1\u606F\u9690\u853D</p><p>OPT\uFF1A\u7406\u60F3\u9875\u9762\u7F6E\u6362\u7B97\u6CD5\uFF08Optimal replacement\uFF09</p><p>LRU\uFF1A\u6700\u8FD1\u6700\u5C11\u4F7F\u7528\u9875\u9762\u7F6E\u6362\u7B97\u6CD5\uFF08Least Recently Used\uFF09</p><p>PSW\uFF1A\u7A0B\u5E8F\u72B6\u6001\u5B57\uFF08Program Status Word\uFF09</p><p>\u7CFB\u7EDF\u4E2D\u5B58\u5728\u4E00\u4E9B\u4E2D\u65AD\uFF0C\u5373\u4F7F\u5728PSW\u4E2D\u88AB\u5C4F\u853D\uFF0C\u5904\u7406\u5668\u4E5F\u4F1A\u54CD\u5E94\u5176\u8BF7\u6C42</p><p>\u7528\u6237\u89C6\u56FE\u770B\u5230\u7684\u6587\u4EF6\u79F0\u903B\u8F91\u6587\u4EF6\uFF0C\u903B\u8F91\u6587\u4EF6\u53EF\u91C7\u7528\u6D41\u5F0F\u6587\u4EF6\u548C\u8BB0\u5F55\u5F0F\u6587\u4EF6\u4E24\u79CD\u7EC4\u7EC7\u65B9\u5F0F</p><p>\u5468\u8F6C\u65F6\u95F4\uFF1A\u4ECE\u4E00\u4E2A\u6279\u5904\u7406\u8FDB\u7A0B\u63D0\u4EA4\u65F6\u523B\u5F00\u59CB\u76F4\u5230\u8BE5\u8FDB\u7A0B\u5B8C\u6210\u65F6\u523B\u4E3A\u6B62\u7684\u7EDF\u8BA1\u5E73\u5747\u65F6\u95F4\uFF08\u5C0F\u6797coding\uFF1A\u8FDB\u7A0B\u8FD0\u884C\u65F6\u95F4+\u8FDB\u7A0B\u7B49\u5F85\u65F6\u95F4\uFF09</p><p>\u5728\u64CD\u4F5C\u7CFB\u7EDF\u8FD0\u884C\u8FC7\u7A0B\u4E2D\uFF0C\u5904\u7406\u5668\u7684\u72B6\u6001\u662F\u52A8\u6001\u6539\u53D8\u7684\uFF0C\u4ECE\u76EE\u6001\u5230\u7BA1\u6001\u7684\u8F6C\u6362\u662F\u901A\u8FC7\u4E2D\u65AD\u5B9E\u73B0\u7684</p><p>\u5982\u679C\u6709\u82E5\u5E72\u8FDB\u7A0B\u5171\u4EAB\u67D0\u4E00\u4E34\u754C\u533A\uFF0C\u5219\u8BE5\u4E34\u754C\u533A\u79F0\u4E3A\u76F8\u5173\u4E34\u754C\u533A</p><p>\u5B58\u50A8\u5206\u533A\u7684\u4FDD\u62A4\u65B9\u6CD5\u6709\u4E24\u79CD\uFF0C\u4E00\u79CD\u662F\u7CFB\u7EDF\u8BBE\u7F6E\u754C\u9650\u5BC4\u5B58\u5668\uFF0C\u53E6\u4E00\u79CD\u662F\u4FDD\u62A4\u952E\u65B9\u6CD5</p><p>\u5728\u64CD\u4F5C\u7CFB\u7EDF\u7684I/O\u8F6F\u4EF6\u4E2D\uFF0C\u91C7\u7528\u6587\u4EF6\u7CFB\u7EDF\u8DEF\u5F84\u540D\u7684\u65B9\u6CD5\u6765\u547D\u540D\u8BBE\u5907</p><p>\u8D44\u6E90\u7684\u5171\u4EAB\u548C\u7ADE\u4E89\u5B58\u5728\u4E8E\u591A\u9053\u7A0B\u5E8F\u7684\u5E76\u53D1\u6267\u884C\u4E2D\uFF0C\u4ECE\u800C\u5236\u7EA6\u4E86\u5404\u9053\u7A0B\u5E8F\u7684\u6267\u884C\u901F\u5EA6\u3002\u7531\u4E8E\u672C\u6765\u5E76\u65E0\u903B\u8F91\u5173\u7CFB\u7684\u7A0B\u5E8F\u4E4B\u95F4\u4EA7\u751F\u4E86\u76F8\u4E92\u5236\u7EA6\u7684\u5173\u7CFB\uFF0C\u800C\u5404\u4E2A\u7A0B\u5E8F\u6D3B\u52A8\u7684\u5DE5\u4F5C\u72B6\u6001\u4E0E\u6240\u5904\u7684\u73AF\u5883\u6709\u5BC6\u5207\u5173\u7CFB\uFF0C\u4F7F\u5E76\u53D1\u7A0B\u5E8F\u7684\u6267\u884C\u51FA\u73B0\u4E86 \u6267\u884C\u2014\u2014\u6682\u505C\u2014\u2014\u6267\u884C \u7684\u6D3B\u52A8\u73B0\u8C61</p><p>\u4FE1\u53F7\uFF08Signal\uFF09\u51FD\u6570\u662FUNIX\u5904\u7406\u5F02\u6B65\u4E8B\u4EF6\u7684\u7ECF\u5178\u65B9\u6CD5</p><p>\u6C38\u4E45\u6027\u8D44\u6E90\uFF08\u53EF\u91CD\u7528\u8D44\u6E90\uFF09\uFF0C\u662F\u6307\u7CFB\u7EDF\u4E2D\u53EF\u4F9B\u8FDB\u7A0B\u91CD\u590D\u4F7F\u7528\u3001\u957F\u671F\u5B58\u5728\u7684\u8D44\u6E90\uFF0C\u5982\u5185\u5B58\u3001\u5916\u90E8\u8BBE\u5907\u3001\u5904\u7406\u5668\u7B49\u786C\u4EF6\u8D44\u6E90\uFF0C\u4EE5\u53CA\u5404\u79CD\u6570\u636E\u6587\u4EF6\u3001\u8868\u683C\u3001\u5171\u4EAB\u7A0B\u5E8F\u4EE3\u7801\u7B49\u8F6F\u4EF6\u8D44\u6E90\uFF1B\u4E34\u65F6\u6027\u8D44\u6E90\uFF08\u6D88\u8017\u578B\u8D44\u6E90\uFF09\uFF0C\u662F\u6307\u7531\u67D0\u4E2A\u8FDB\u7A0B\u6240\u4EA7\u751F\uFF0C\u53EA\u4E3A\u53E6\u4E00\u4E2A\u8FDB\u7A0B\u4F7F\u7528\u4E00\u6B21\u6216\u7ECF\u8FC7\u77ED\u6682\u65F6\u95F4\u540E\u4FBF\u4E0D\u518D\u4F7F\u7528\u7684\u8D44\u6E90\uFF0C\u5982I/O\u548C\u65F6\u949F\u4E2D\u65AD\u4FE1\u53F7\u3001\u540C\u6B65\u4FE1\u53F7\u3001\u6D88\u606F\u7B49</p><p>\u6309\u9700\u5206\u914D\u8D44\u6E90\u662F\u4E3A\u4E86\u6B7B\u9501\u7684\u9884\u9632</p><p>\u5982\u679C\u8D44\u6E90\u5206\u914D\u56FE\u4E2D\u51FA\u73B0\u4E86\u73AF\u8DEF\uFF0C\u5219\u7CFB\u7EDF\u4E2D\u53EF\u80FD\u5B58\u5728\u6B7B\u9501\u3002\u5982\u679C\u5904\u4E8E\u73AF\u8DEF\u4E2D\u7684\u6BCF\u4E2A\u8D44\u6E90\u7C7B\u4E2D\u5747\u53EA\u6709\u4E00\u4E2A\u8D44\u6E90\u5B9E\u4F8B\uFF0C\u5219\u73AF\u8DEF\u7684\u5B58\u5728\u5373\u610F\u5473\u7740\u6B7B\u9501\u7684\u5B58\u5728\u3002\u6B64\u65F6\uFF0C\u73AF\u8DEF\u662F\u6B7B\u9501\u7684\u5145\u5206\u5FC5\u8981\u6761\u4EF6</p><p>\u5728\u8D44\u6E90\u5206\u914D\u56FE\u4E2D\uFF0C\u5982\u679C\u5904\u4E8E\u73AF\u8DEF\u4E2D\u7684\u6BCF\u4E2A\u8D44\u6E90\u7C7B\u4E2D\u8D44\u6E90\u5B9E\u4F8B\u7684\u4E2A\u6570\u4E0D\u5168\u4E3A1,\u6B64\u65F6\uFF0C\u73AF\u8DEF\u662F\u6B7B\u9501\u7684\u5FC5\u8981\u6761\u4EF6</p><p>\u64CD\u4F5C\u7CFB\u7EDF\u7684\u8BBE\u8BA1\u8FC7\u7A0B\u4E00\u822C\u53EF\u5206\u4E3A\u4E09\u4E2A\u90E8\u5206\uFF1A\u529F\u80FD\u8BBE\u8BA1\u3001\u7B97\u6CD5\u8BBE\u8BA1\u548C\u7ED3\u6784\u8BBE\u8BA1</p><p>\u5B58\u50A8\u7684\u6700\u5C0F\u5355\u4F4D\u79F0\u4E3A\u201C\u4E8C\u8FDB\u4F4D\u201D\u3002\u5B58\u50A8\u5668\u7684\u6700\u5C0F\u7F16\u5740\u5355\u4F4D\u662F\u5B57\u8282</p><p>\u4E3A\u4E86\u4ECE\u64CD\u4F5C\u7CFB\u7EDF\u4E2D\u83B7\u5F97\u670D\u52A1\uFF0C\u7528\u6237\u7A0B\u5E8F\u5FC5\u987B\u4F7F\u7528\u7CFB\u7EDF\u8C03\u7528\uFF0C\u7CFB\u7EDF\u8C03\u7528\u9677\u5165\u5185\u6838\u5E76\u8C03\u7528\u64CD\u4F5C\u7CFB\u7EDF\u3002\u8BBF\u95EE\u6307\u4EE4\u628A\u76EE\u6001\u5207\u6362\u6210\u7BA1\u6001\uFF0C\u5E76\u542F\u7528\u64CD\u4F5C\u7CFB\u7EDF</p><p>\u5728\u8FDB\u7A0B\u4E2D\u8BBF\u95EE\u4E34\u754C\u8D44\u6E90\u7684\u7A0B\u5E8F\u79F0\u4E3A\u4E34\u754C\u533A</p><p>\u4E92\u65A5\u4FE1\u53F7\u91CF\uFF0C\u521D\u503C\u4E3A1\uFF0C\u7528\u4E8E\u4E92\u65A5\u8BBF\u95EE\u6D88\u606F\u961F\u5217\uFF1B\u540C\u6B65\u4FE1\u53F7\u91CF\uFF0C\u521D\u503C\u4E3A0\uFF0C\u7528\u4E8E\u6D88\u606F\u8BA1\u6570</p><p>\u6210\u7EC4\u94FE\u63A5\u8FD9\u79CD\u65B9\u6848\u80FD\u591F\u8FC5\u901F\u627E\u5230\u5927\u91CF\u7A7A\u95F2\u76D8\u5757\u5730\u5740</p><p>\u82E5\u4EE5\u7CFB\u7EDF\u4E2D\u4FE1\u606F\u7EC4\u7EC7\u65B9\u5F0F\u6765\u5212\u5206\u8BBE\u5907\uFF0C\u53EF\u5C06I/O\u8BBE\u5907\u5212\u5206\u4E3A\u5B57\u7B26\u8BBE\u5907\u548C\u5757\u8BBE\u5907</p><p>\u987A\u5E8F\u6027\u3001\u5C01\u95ED\u6027\u662F\u7A0B\u5E8F\u987A\u5E8F\u6267\u884C\u65F6\u7684\u57FA\u672C\u7279\u6027\uFF0C\u7531\u6B64\u53EF\u4EE5\u5F15\u51FA\u7A0B\u5E8F\u987A\u5E8F\u6267\u884C\u65F6\uFF0C\u5176\u6267\u884C\u7ED3\u679C\u5177\u6709\u4E24\u4E2A\u7279\u6027\uFF0C\u5373\u6267\u884C\u7ED3\u679C\u7684\u786E\u5B9A\u6027\u548C\u53EF\u518D\u73B0\u6027</p><p>\u4ECE\u9759\u6001\u7684\u89D2\u5EA6\u770B\uFF0C\u8FDB\u7A0B\u662F\u7531\u6570\u636E\u3001\u7A0B\u5E8F\u548C\u8FDB\u7A0B\u63A7\u5236\u5757(PCB)\u4E09\u4E2A\u90E8\u5206\u7EC4\u6210\u7684</p><p>\u4E00\u4E2A\u7BA1\u7A0B\u7531\u56DB\u90E8\u5206\u7EC4\u6210\uFF0C\u5206\u522B\u4E3A\u7BA1\u7A0B\u540D\u79F0\u3001\u5171\u4EAB\u6570\u636E\u7684\u8BF4\u660E\u3001\u5BF9\u6570\u636E\u8FDB\u884C\u64CD\u4F5C\u7684\u4E00\u7EC4\u8FC7\u7A0B\u548C\u5BF9\u5171\u4EAB\u6570\u636E\u7684\u521D\u59CB\u5316\u4EE3\u7801</p><p>\u5728\u54F2\u5B66\u5BB6\u5C31\u9910\u95EE\u9898\u4E2D\uFF0C\u4E3A\u9632\u6B62\u6B7B\u9501\u7684\u4EA7\u751F\uFF0C\u53EF\u4EE5\u91C7\u7528\u8D44\u6E90\u7684\u6709\u5E8F\u5206\u914D\u6CD5\uFF0C\u5373\u89C4\u5B9A\u6BCF\u4E2A\u54F2\u5B66\u5BB6\u60F3\u7528\u9910\u65F6\u603B\u662F\u5148\u62FF\u7F16\u53F7\u5C0F\u7684\u7B77\u5B50\u518D\u62FF\u7F16\u53F7\u5927\u7684\u7B77\u5B50\u5C31\u4E0D\u4F1A\u51FA\u73B0\u6B7B\u9501\u73B0\u8C61</p><p>\u5206\u533A\u7BA1\u7406\u662F\u4E00\u79CD\u80FD\u591F\u6EE1\u8DB3\u591A\u9053\u7A0B\u5E8F\u8FD0\u884C\u7684\u6700\u7B80\u5355\u7684\u5B58\u50A8\u7BA1\u7406\u65B9\u6848\uFF0C\u6709\u4E24\u79CD\u5206\u533A\u65B9\u5F0F\uFF0C\u5206\u522B\u4E3A\u56FA\u5B9A\u5206\u533A\u548C\u53EF\u53D8\u5206\u533A</p><p>\u8BA1\u7B97\u673A\u7CFB\u7EDF\u4E2D\u4E00\u7EC4\u5E26\u6807\u8BC6\u7684\u3001\u903B\u8F91\u4E0A\u6709\u5B8C\u6574\u610F\u4E49\u7684\u4FE1\u606F\u9879\u7684\u5E8F\u5217\u79F0\u4E3A\u6587\u4EF6</p><p>Windows\u7CFB\u7EDF\u7684FAT\u6587\u4EF6\u7CFB\u7EDF\u91C7\u7528\u7684\u6587\u4EF6\u7269\u7406\u7ED3\u6784\u662F\u94FE\u63A5\u7ED3\u6784</p><p>\u542F\u52A8\u78C1\u76D8\u6267\u884C\u8F93\u5165\u8F93\u51FA\u65F6\uFF0C\u6267\u884C\u4E00\u6B21\u8F93\u5165\u8F93\u51FA\u6240\u82B1\u7684\u65F6\u95F4\u5305\u62EC\u5BFB\u627E\u65F6\u95F4\u3001\u5EF6\u8FDF\u65F6\u95F4\u548C\u4F20\u9001\u65F6\u95F4</p><p>\u901A\u4FE1\u89C4\u8303\u5316\u4E3B\u8981\u662F\u6307\u6A21\u5757\u4E4B\u95F4\u7684\u63A5\u53E3\u5E94\u8BE5\u6E05\u6670\u5212\u4E00\uFF0C\u6A21\u5757\u7684\u8054\u7CFB\u65B9\u5F0F\u8981\u7EDF\u4E00\uFF0C\u8FD9\u662F\u6807\u51C6\u5316\u7684\u4E00\u79CD\u65B9\u5F0F</p><p>\u6BCF\u5F53\u5B58\u50A8\u5668\u8981\u8BBF\u95EE\u5185\u5B58\u65F6\uFF0C\u786C\u4EF6\u81EA\u52A8\u5C06\u88AB\u8BBF\u95EE\u7684\u5185\u5B58\u5730\u5740\u4E0E\u754C\u9650\u5BC4\u5B58\u5668\u7684\u5185\u5BB9\u8FDB\u884C\u6BD4\u8F83\uFF0C\u4EE5\u5224\u65AD\u662F\u5426\u8D8A\u754C\u3002\u5982\u679C\u672A\u8D8A\u754C\uFF0C\u5219\u6309\u6B64\u5730\u5740\u8BBF\u95EE\u5185\u5B58\uFF0C\u5426\u5219\u5C06\u4EA7\u751F\u7A0B\u5E8F\u4E2D\u65AD\u2014\u2014\u8D8A\u754C\u4E2D\u65AD\u6216\u79F0\u4E3A\u5B58\u50A8\u4FDD\u62A4\u4E2D\u65AD</p><p>\u8D44\u6E90\u6709\u5E8F\u5206\u914D\u6CD5\u53EF\u4EE5\u7528\u6765\u9884\u9632\u6B7B\u9501\u3002\u94F6\u884C\u5BB6\u7B97\u6CD5\u662F\u6700\u8457\u540D\u7684\u6B7B\u9501\u907F\u514D\u7B97\u6CD5\u3002\u64A4\u9500\u8FDB\u7A0B\u6CD5\u5C5E\u4E8E\u6B7B\u9501\u7684\u89E3\u9664\u65B9\u6CD5\u3002\u8D44\u6E90\u5206\u914D\u56FE\u5316\u7B80\u65B9\u6CD5\u53EF\u4EE5\u88AB\u7528\u6765\u68C0\u6D4B\u7CFB\u7EDF\u662F\u5426\u4E3A\u6B7B\u9501\u72B6\u6001</p><p>\u5B58\u50A8\u4FDD\u62A4\u7684\u76EE\u7684\u5728\u4E8E\u591A\u4E2A\u7A0B\u5E8F\u5171\u4EAB\u5185\u5B58\u63D0\u4F9B\u4FDD\u969C\uFF0C\u4F7F\u5728\u5185\u5B58\u4E2D\u7684\u5404\u9053\u7A0B\u5E8F\uFF0C\u53EA\u80FD\u8BBF\u95EE\u5B83\u81EA\u5DF1\u7684\u533A\u57DF\uFF0C\u907F\u514D\u5404\u9053\u7A0B\u5E8F\u95F4\u76F8\u4E92\u5E72\u6270</p><p>\u76EE\u5F55\u9879\u5206\u89E3\u6CD5\u8BA1\u7B97\u5E73\u5747\u8BBF\u76D8\u6B21\u6570\uFF1A(1+n)/2 + 1 \u5176\u4E2D\u7B2C\u4E00\u4E2A1\u8868\u793A\u6700\u4F18\u60C5\u51B5\uFF0Cn\u8868\u793A\u6700\u574F\u60C5\u51B5\uFF0C\u540E\u9762\u7684+1\u662F\u8BBF\u95EE\u5230\u7B26\u53F7\u76EE\u5F55\u9879\u67E5\u627E\u57FA\u672C\u76EE\u5F55\u9879\uFF0C\u6700\u597D\u548C\u6700\u574F\u60C5\u51B5\u90FD\u5FC5\u987B\u7684\u4E00\u6B21\u8BBF\u95EE\uFF0C\u6700\u4F18\u52A0\u6700\u574F\u9664\u4EE5\u4E8C\u5F97\u5230\u5E73\u5747\u8BBF\u76D8\u6B21\u6570\u3002n\u503C\u8BA1\u7B97\uFF1A\u603B\u76EE\u5F55\u6570/\uFF08\u7269\u7406\u5757\u5927\u5C0F/\u7B26\u53F7\u76EE\u5F55\u9879\u5927\u5C0F\uFF09</p><p>\u5171\u4EAB\u6027\u662F\u6307\u64CD\u4F5C\u7CFB\u7EDF\u7A0B\u5E8F\u4E0E\u591A\u4E2A\u7528\u6237\u7A0B\u5E8F\u5171\u7528\u64CD\u4F5C\u7CFB\u7EDF\u4E2D\u7684\u5404\u79CD\u8D44\u6E90\uFF0C\u8FD9\u79CD\u5171\u4EAB\u6027\u662F\u5728\u64CD\u4F5C\u7CFB\u7EDF\u63A7\u5236\u4E0B\u5B9E\u73B0\u7684</p><p>\u5728\u591A\u9053\u7A0B\u5E8F\u73AF\u5883\u4E2D\uFF0C\u7531\u4E8E\u7CFB\u7EDF\u8D44\u6E90\u7684\u5171\u4EAB\u548C\u7ADE\u4E89\uFF0C\u672C\u6765\u5E76\u65E0\u903B\u8F91\u5173\u7CFB\u7684\u7A0B\u5E8F\u4E4B\u95F4\u4EA7\u751F\u4E86\u76F8\u4E92\u5236\u7EA6\u7684\u5173\u7CFB</p><p>\u5728\u4E03\u72B6\u6001\u8FDB\u7A0B\u6A21\u578B\u4E2D\uFF0C\u88AB\u5BF9\u6362\u81F3\u5916\u5B58\u7684\u8FDB\u7A0B\u53EF\u80FD\u5904\u4E8E\u4E24\u79CD\u8FDB\u7A0B\u72B6\u6001\u4E4B\u4E00\uFF0C\u5373\u5C31\u7EEA\u6302\u8D77\u72B6\u6001\u548C\u963B\u585E\u6302\u8D77\u72B6\u6001</p><p>\u91C7\u7528\u5171\u4EAB\u6587\u4EF6\u89E3\u51B3\u8FDB\u7A0B\u4E4B\u95F4\u7684\u5927\u91CF\u4FE1\u606F\u4EA4\u6362\u7684\u901A\u4FE1\u65B9\u5F0F\u79F0\u4E3A\u7BA1\u9053\u901A\u4FE1</p><p>\u6B7B\u9501\u7684\u89E3\u9664\u65B9\u6CD5\u5206\u4E3A\u4E24\u5927\u7C7B\uFF0C\u5373\u5265\u593A\u8D44\u6E90\u548C\u64A4\u9500\u8FDB\u7A0B</p><p>\u9875\u5F0F\u5B58\u50A8\u7BA1\u7406\u8981\u6C42\u5BF9\u7A0B\u5E8F\u4E2D\u7684\u903B\u8F91\u5730\u5740\u7A7A\u95F4\u8FDB\u884C\u5206\u9875\uFF0C\u4E8E\u662F\u7CFB\u7EDF\u63D0\u4F9B\u7ED9\u7F16\u7A0B\u4F7F\u7528\u7684\u903B\u8F91\u5730\u5740\u53EF\u7531\u4E24\u90E8\u5206\u7EC4\u6210\uFF1A\u865A\u62DF\u9875\u53F7\u548C\u9875\u5185\u5730\u5740</p><p>\u6587\u4EF6\u7684\u7269\u7406\u7ED3\u6784\u91C7\u7528\u7D22\u5F15\u7ED3\u6784\u80FD\u591F\u652F\u6301\u6587\u4EF6\u63D2\u5165\u3001\u5220\u9664\u8981\u6C42\uFF0C\u9002\u5408\u987A\u5E8F\u5B58\u53D6\uFF0C\u4E5F\u9002\u5408\u968F\u673A\u5B58\u53D6</p><p>\u6309\u8BBE\u5907\u4F7F\u7528\u53EF\u5171\u4EAB\u6027\u5206\u7C7B\uFF0C\u53EF\u5C06I/O\u8BBE\u5907\u5206\u4E3A\u72EC\u5360\u8BBE\u5907\u3001\u5171\u4EAB\u8BBE\u5907\u548C\u865A\u62DF\u8BBE\u5907</p><p>\u6B63\u5728\u8FD0\u884C\u7684\u8FDB\u7A0B\uFF0C\u7531\u4E8E\u89C4\u5B9A\u7684\u65F6\u95F4\u7247\u7528\u5B8C\u800C\u4F7F\u5F97\u7CFB\u7EDF\u53D1\u51FA\u8D85\u65F6\u4E2D\u65AD\u8BF7\u6C42\uFF0C\u6B64\u65F6\u8FDB\u7A0B\u72B6\u6001\u5C06\u88AB\u4FEE\u6539\u4E3A\u5C31\u7EEA\u72B6\u6001</p><p>UNIX\u7CFB\u7EDF\u4E2D\u7236\u8FDB\u7A0B\u4F7F\u7528fork\u51FD\u6570\u521B\u5EFA\u5B50\u8FDB\u7A0B\u540E\uFF0C\u65B0\u521B\u5EFA\u7684\u5B50\u8FDB\u7A0B\u590D\u5236\u4E86\u7236\u8FDB\u7A0B\u7528\u6237\u5730\u5740\u7A7A\u95F4\u7684\u5185\u5BB9</p><p>\u5E76\u53D1\u8FDB\u7A0B\u8FD0\u884C\u65F6\u4EA7\u751F\u201C\u4E0E\u65F6\u95F4\u6709\u5173\u7684\u9519\u8BEF\u201D\u7684\u6839\u672C\u539F\u56E0\u5728\u4E8E\u7A0B\u5E8F\u4E2D\u5171\u4EAB\u4E86\u516C\u5171\u53D8\u91CF</p><p>\u82E5\u5728\u7CFB\u7EDF\u4E2D\u7684\u67D0\u4E9B\u8D44\u6E90\u4E00\u6B21\u53EA\u5141\u8BB8\u4E00\u4E2A\u8FDB\u7A0B\u4F7F\u7528\uFF0C\u5219\u8FD9\u7C7B\u8D44\u6E90\u79F0\u4E3A\u4E34\u754C\u8D44\u6E90\u6216\u5171\u4EAB\u53D8\u91CF\uFF0C\u800C\u5728\u8FDB\u7A0B\u4E2D\u8BBF\u95EE\u4E34\u754C\u8D44\u6E90\u7684\u7A0B\u5E8F\u79F0\u4E3A\u4E34\u754C\u533A</p><p>\u540C\u4E00\u4E2A\u8FDB\u7A0B\u7684\u591A\u4E2A\u7EBF\u7A0B\u5171\u4EAB\u8BE5\u8FDB\u7A0B\u7684\u5185\u5B58\u5730\u5740\u7A7A\u95F4\u548C\u6587\u4EF6\uFF0C\u5B83\u4EEC\u4E4B\u95F4\u7684\u540C\u6B65\u548C\u901A\u4FE1\u65E0\u9700\u8C03\u7528\u5185\u6838\uFF0C\u5B9E\u73B0\u5BB9\u6613\u4E14\u5F00\u9500\u5C0F</p><p>\u4E3A\u5B9E\u73B0\u8FDB\u7A0B\u7BA1\u7406\uFF0C\u7CFB\u7EDF\u91C7\u7528\u94FE\u63A5\u65B9\u5F0F\u5BF9\u6240\u6709\u7684\u8FDB\u7A0B\u63A7\u5236\u5757(PCB)\u8FDB\u884C\u7EC4\u7EC7\u3002\u5176\u4E2D\uFF0C\u5355\u5411\u94FE\u63A5\u65B9\u5F0F\u53EA\u6709\u4E00\u4E2A\u6307\u9488\uFF0C\u524D\u4E00\u8FDB\u7A0B\u7684PCB\u4E2D\u7684\u6307\u9488\u503C\u4E3A\u4E0B\u4E00\u4E2A\u8FDB\u7A0B\u7684PCB\u7684\u5730\u5740\uFF1B\u53CC\u5411\u94FE\u63A5\u65B9\u5F0F\u5305\u542B2\u4E2A\u6307\u9488\uFF0C\u5206\u522B\u6307\u5411\u524D\u4E00\u4E2A\u8FDB\u7A0B\u7684PCB\u7684\u5730\u5740\u548C\u540E\u4E00\u4E2A\u8FDB\u7A0B\u7684PCB\u7684\u5730\u5740</p><p>\u68C0\u6D4B\u6B7B\u9501\u7684\u5B9E\u8D28\u662F\u786E\u5B9A\u662F\u5426\u5B58\u5728\u4EA7\u751F\u6B7B\u9501\u56DB\u4E2A\u5FC5\u8981\u6761\u4EF6\u4E2D\u7684\u5FAA\u73AF\u7B49\u5F85\u6761\u4EF6</p><p>\u4E3A\u4E86\u89E3\u51B3\u865A\u62DF\u9875\u5F0F\u5B58\u50A8\u4E2D\u7684\u98A0\u7C38\u95EE\u9898\uFF0C\u53EF\u4EE5\u91C7\u7528\u5DE5\u4F5C\u96C6\u6A21\u578B\u3002\u5BF9\u4E8E\u7ED9\u5B9A\u7684\u8FDB\u7A0B\u8BBF\u95EE\u5E8F\u5217\uFF0C\u4ECE\u65F6\u523B(t-\u2206)\u5230\u65F6\u523Bt\u4E4B\u95F4\u6240\u8BBF\u95EE\u9875\u9762\u7684\u96C6\u5408\uFF0C\u79F0\u4E3A\u8BE5\u8FDB\u7A0B\u7684\u5DE5\u4F5C\u96C6\uFF0C\u2206\u79F0\u4E3A\u5DE5\u4F5C\u96C6\u7A97\u53E3</p><p>\u91C7\u7528\u53EF\u53D8\u5206\u533A\u65B9\u5F0F\u8FDB\u884C\u5B58\u50A8\u7BA1\u7406\u65F6\uFF0C\u9700\u8981\u6709\u786C\u4EF6\u7684\u5730\u5740\u8F6C\u6362\u673A\u6784\u8FDB\u884C\u652F\u6301\uFF0C\u5176\u4E2D\u57FA\u5740\u5BC4\u5B58\u5668\u7528\u6765\u5B58\u50A8\u7A0B\u5E8F\u6240\u5360\u5206\u533A\u7684\u8D77\u59CB\u5730\u5740\uFF0C\u9650\u957F\u5BC4\u5B58\u5668\u5219\u7528\u6765\u5B58\u50A8\u7A0B\u5E8F\u6240\u5360\u5206\u533A\u7684\u957F\u5EA6</p><p>\u628A\u82E5\u5E72\u4E2A\u903B\u8F91\u8BB0\u5F55\u5408\u6210\u4E00\u7EC4\u5E76\u5B58\u50A8\u4E8E\u4E00\u7269\u7406\u5757\u7684\u5DE5\u4F5C\u79F0\u8BB0\u5F55\u7684\u6210\u7EC4\uFF0C\u6BCF\u5757\u4E2D\u7684\u903B\u8F91\u8BB0\u5F55\u4E2A\u6570\u79F0\u5757\u56E0\u5B50</p><p>\u5728UNIX\u7CFB\u7EDF\u7684\u6587\u4EF6\u5B58\u53D6\u6743\u9650\u63A7\u5236\u65B9\u6848\u4E2D\uFF0C\u628A\u7528\u6237\u5206\u4E3A\u6587\u4EF6\u4E3B\u3001\u6587\u4EF6\u4E3B\u7684\u540C\u7EC4\u7528\u6237\u548C\u5176\u4ED6\u7528\u6237\u4E09\u7C7B\uFF0C\u53EF\u4EE5\u5BF9\u8FD9\u4E09\u7C7B\u7528\u6237\u5206\u522B\u8BBE\u7F6E\u4E0D\u540C\u7684\u5B58\u53D6\u6743\u9650</p><p>\u8BBE\u5907\u5206\u914D\u901A\u5E38\u91C7\u7528\u5148\u6765\u5148\u670D\u52A1\u548C\u9AD8\u4F18\u5148\u7EA7\u4F18\u5148\u4E24\u79CD\u65B9\u6CD5\uFF0C\u5176\u4E2D\uFF0C\u524D\u4E00\u79CD\u65B9\u6CD5\u662F\u6309\u7167\u8FDB\u7A0B\u63D0\u51FA\u65F6\u95F4\u5148\u540E\u8FDB\u884C\u6392\u961F\uFF0C\u5E76\u603B\u662F\u628A\u8BBE\u5907\u9996\u5148\u5206\u914D\u7ED9\u6392\u5728\u961F\u9996\u7684\u8FDB\u7A0B</p><p>\u901A\u8FC7\u589E\u52A0\u8D44\u6E90\u6570\u91CF\u7684\u65B9\u6CD5\u53EF\u4EE5\u9884\u9632\u6B7B\u9501\uFF0C\u56E0\u4E3A\u8BE5\u65B9\u6CD5\u80FD\u6253\u7834\u6B7B\u9501\u5FC5\u8981\u6761\u4EF6\u4E2D\u7684\u4E92\u65A5\u6761\u4EF6</p><p>\u94F6\u884C\u5BB6\u7B97\u6CD5\uFF1A\u8FDB\u7A0B\u9996\u5148\u63D0\u51FA\u5BF9\u8D44\u6E90\u7684\u6700\u5927\u9700\u6C42\u91CF\uFF0C\u5F53\u8FDB\u7A0B\u5728\u6267\u884C\u4E2D\u6BCF\u6B21\u7533\u8BF7\u8D44\u6E90\u65F6\uFF0C\u7CFB\u7EDF\u6D4B\u8BD5\u8BE5\u8FDB\u7A0B\u5DF2\u5360\u7528\u7684\u8D44\u6E90\u4E0E\u672C\u6B21\u7533\u8BF7\u7684\u8D44\u6E90\u6570\u4E4B\u548C\u662F\u5426\u8D85\u8FC7\u4E86\u8BE5\u8FDB\u7A0B\u5BF9\u8D44\u6E90\u7684\u6700\u5927\u9700\u6C42\u91CF\u3002\u82E5\u8D85\u8FC7\u5219\u62D2\u7EDD\u5206\u914D\u8D44\u6E90\uFF0C\u82E5\u6CA1\u6709\u8D85\u8FC7\uFF0C\u5219\u7CFB\u7EDF\u518D\u6D4B\u8BD5\u7CFB\u7EDF\u73B0\u5B58\u7684\u8D44\u6E90\u80FD\u5426\u6EE1\u8DB3\u8BE5\u8FDB\u7A0B\u5C1A\u9700\u7684<strong>\u6700\u5927</strong>\u8D44\u6E90\u91CF\uFF0C\u82E5\u80FD\u6EE1\u8DB3\u5219\u6309\u5F53\u524D\u7684\u7533\u8BF7\u91CF\u5206\u914D\u8D44\u6E90\uFF0C\u5426\u5219\u4E5F\u8981\u63A8\u8FDF\u5206\u914D</p><p>\u901F\u5EA6\uFF1A\u5BC4\u5B58\u5668 &gt; \u9AD8\u901F\u7F13\u5B58</p><p>\u94FE\u63A5\u7ED3\u6784\u7684\u4F18\u70B9\uFF1A\u5B58\u50A8\u788E\u7247\u95EE\u9898\u89E3\u51B3\u4E86\uFF0C\u6709\u5229\u4E8E\u6587\u4EF6\u52A8\u6001\u6269\u5145\uFF0C\u6709\u5229\u4E8E\u6587\u4EF6\u63D2\u5165\u548C\u5220\u9664\uFF0C\u63D0\u9AD8\u4E86\u78C1\u76D8\u7A7A\u95F4\u5229\u7528\u7387\u3002\u94FE\u63A5\u7ED3\u6784\u7684\u7F3A\u70B9\uFF1A\u5B58\u53D6\u901F\u5EA6\u6162\uFF0C\u4E0D\u9002\u4E8E\u968F\u673A\u5B58\u53D6\u6587\u4EF6\uFF1B\u78C1\u76D8\u7684\u78C1\u5934\u79FB\u52A8\u591A\uFF0C\u6548\u7387\u76F8\u5BF9\u8F83\u4F4E\uFF1B\u5B58\u5728\u6587\u4EF6\u7684\u53EF\u9760\u6027\u95EE\u9898\uFF0C\u6BD4\u5982\u6307\u9488\u51FA\u9519\uFF0C\u6587\u4EF6\u4E5F\u5C31\u51FA\u9519\u4E86\uFF1B\u53E6\u5916\uFF0C\u94FE\u63A5\u6307\u9488\u9700\u8981\u5360\u7528\u4E00\u5B9A\u7684\u7A7A\u95F4</p><p>Windows\u4F53\u7CFB\u7ED3\u6784\u7684\u4E3B\u8981\u5C42\u6B21\u4E2D\uFF0C\u6267\u884C\u64CD\u4F5C\u7CFB\u7EDF\u4E2D\u6700\u57FA\u672C\u7684\u64CD\u4F5C\u4E14\u4F7F\u7528\u8FD0\u884C\u5728\u6838\u5FC3\u6001\u7684\u662F\u5185\u6838\uFF0C\u9690\u85CF\u4E86\u4E0E\u786C\u4EF6\u6709\u5173\u7684\u7EC6\u8282\uFF0C\u4E3A\u64CD\u4F5C\u7CFB\u7EDF\u7684\u786C\u4EF6\u5E73\u53F0\u63D0\u4F9B\u4F4E\u7EA7\u63A5\u53E3\u7684\u662F\u786C\u4EF6\u62BD\u8C61\u5C42(HAL)</p><p>\u7EBF\u7A0B\u7684\u5B9E\u73B0\u65B9\u5F0F\u6709\u4E24\u79CD\uFF0C\u5206\u522B\u662F\u7528\u6237\u7EA7\u7EBF\u7A0B\u548C\u5185\u6838\u7EA7\u7EBF\u7A0B</p><p>\u8FDB\u7A0B\u63A7\u5236\u901A\u5E38\u91C7\u7528\u539F\u8BED\u6765\u5B9E\u73B0\uFF0C\u5F53\u9700\u8981\u4EA7\u751F\u4E00\u4E2A\u65B0\u8FDB\u7A0B\u65F6\uFF0C\u7CFB\u7EDF\u4F7F\u7528\u521B\u5EFA\u539F\u8BED\uFF1B\u5F53\u8BE5\u8FDB\u7A0B\u5B8C\u6210\u4EFB\u52A1\u540E\uFF0C\u7CFB\u7EDF\u4F7F\u7528\u64A4\u9500\u539F\u8BED\u6765\u7ED3\u675F\u8FDB\u7A0B</p><p>\u7BA1\u7A0B\u80FD\u4FDD\u969C\u5171\u4EAB\u8D44\u6E90\u7684\u4E92\u65A5\u6267\u884C\uFF0C\u5373\u4E00\u4E2A\u7BA1\u7A0B\u4E2D\u6D3B\u52A8\u7684\u8FDB\u7A0B\u6570\u6700\u5927\u4E3A1\u4E2A</p><p>\u6309\u6587\u4EF6\u7684\u7528\u9014\u53EF\u628A\u6587\u4EF6\u5206\u4E3A\u7CFB\u7EDF\u6587\u4EF6\u3001\u5E93\u51FD\u6570\u6587\u4EF6\u548C\u7528\u6237\u6587\u4EF6\u4E09\u7C7B</p><p>\u5BF9\u78C1\u76D8\u7A7A\u95F2\u5757\u7684\u7BA1\u7406\u901A\u5E38\u6709\u56DB\u79CD\u65B9\u6848\uFF0C\u5206\u522B\u4E3A\u4F4D\u793A\u56FE\u3001\u7A7A\u95F2\u5757\u8868\u3001\u7A7A\u95F2\u5757\u94FE\u8868\u4EE5\u53CA\u5728\u6B64\u57FA\u7840\u4E0A\u7684\u6539\u8FDB\u65B9\u6848\uFF1A\u7A7A\u95F2\u5757\u6210\u7EC4\u94FE\u63A5\u6CD5</p><p>I/O\u8F6F\u4EF6\u7ED3\u6784\u4E00\u822C\u5206\u4E3A\u56DB\u5C42\uFF1A\u4E2D\u65AD\u5904\u7406\u7A0B\u5E8F\u3001\u8BBE\u5907\u9A71\u52A8\u7A0B\u5E8F\u3001\u8BBE\u5907\u72EC\u7ACB\u7684\u64CD\u4F5C\u7CFB\u7EDF\u8F6F\u4EF6\u548C\u7528\u6237\u7EA7\u8F6F\u4EF6</p><p>CF\u4E3A\u8FDB\u4F4D\u6807\u5FD7\u4F4D\uFF0CZF\u4E3A\u96F6\u6807\u5FD7\u4F4D\uFF0CSF\u4E3A\u7B26\u53F7\u6807\u5FD7\u4F4D\uFF0COF\u4E3A\u6EA2\u51FA\u6807\u5FD7\u4F4D</p><p>\u521B\u5EFA\u4E00\u4E2A\u76EE\u5F55\u5C5E\u4E8E\u6587\u4EF6\u64CD\u4F5C\u7C7B\u7CFB\u7EDF\u8C03\u7528</p><p>\u5B9E\u73B0\u8FDB\u7A0B\u540C\u6B65\u7684\u673A\u5236\u79F0\u4E3A\u540C\u6B65\u673A\u5236</p><p>\u4E24\u4E2A\u8FDB\u7A0B\u4E89\u593A\u540C\u4E00\u4E2A\u8D44\u6E90\uFF0C\u4E0D\u4E00\u5B9A\u4EA7\u751F\u6B7B\u9501</p><p>\u8D44\u6E90\u5206\u914D\u56FE\u662F\u4E00\u4E2A\u6709\u5411\u56FE\uFF0C\u5706\u5708\u8868\u793A\u8FDB\u7A0B\uFF0C\u65B9\u6846\u8868\u793A\u6BCF\u7C7B\u8D44\u6E90\uFF0C\u7533\u8BF7\u8FB9\u4E3A\u4ECE\u8FDB\u7A0B\u5230\u8D44\u6E90\u7684\u6709\u5411\u8FB9\uFF0C\u5206\u914D\u8FB9\u4E3A\u4ECE\u8D44\u6E90\u5230\u8FDB\u7A0B\u7684\u6709\u5411\u8FB9</p><p>\u7D22\u5F15\u7ED3\u6784\u4FDD\u6301\u4E86\u94FE\u63A5\u7ED3\u6784\u7684\u4F18\u70B9\uFF0C\u53C8\u89E3\u51B3\u4E86\u5176\u7F3A\u70B9\uFF1B\u7D22\u5F15\u6587\u4EF6\u53EF\u4EE5\u6EE1\u8DB3\u6587\u4EF6\u52A8\u6001\u589E\u957F\u7684\u8981\u6C42\uFF1B\u7D22\u5F15\u6587\u4EF6\u53EF\u4EE5\u5145\u5206\u5229\u7528\u5916\u5B58\u7A7A\u95F4\uFF1B\u7D22\u5F15\u7ED3\u6784\u6587\u4EF6\u65E2\u9002\u4E8E\u987A\u5E8F\u5B58\u53D6\uFF0C\u4E5F\u9002\u4E8E\u968F\u673A\u5B58\u53D6</p><p>\u5728\u8BA1\u7B97\u673A\u7CFB\u7EDF\u4E2D\uFF0C\u5BF9\u8D44\u6E90\u7684\u5171\u4EAB\u4E00\u822C\u6709\u4E24\u79CD\u5F62\u5F0F\uFF1A\u4E92\u65A5\u5171\u4EAB\u548C\u540C\u65F6\u5171\u4EAB</p><p>\u5F53\u4E2D\u592E\u5904\u7406\u5668\u5904\u4E8E\u76EE\u6001\u65F6\u4E0D\u5141\u8BB8\u6267\u884C\u7279\u6743\u6307\u4EE4</p><p>\u6B7B\u9501\u9884\u9632\u7684\u57FA\u672C\u601D\u60F3\u662F\u9632\u60A3\u4E8E\u672A\u7136</p><p>\u9875\u5F0F\u5B58\u50A8\u5668\u63D0\u4F9B\u7F16\u7A0B\u4F7F\u7528\u7684\u865A\u62DF\u5730\u5740\u7531\u4E24\u90E8\u5206\u7EC4\u6210\uFF1A\u865A\u62DF\u9875\u53F7\u548C\u9875\u5185\u5730\u5740</p><p>\u6839\u636E\u7CFB\u7EDF\u8BBE\u7F6E\u7684\u7F13\u51B2\u533A\u7684\u4E2A\u6570\uFF0C\u53EF\u628A\u7F13\u51B2\u6280\u672F\u5206\u4E3A\u5355\u7F13\u51B2\u3001\u53CC\u7F13\u51B2\u548C\u591A\u7F13\u51B2\u4EE5\u53CA\u7F13\u51B2\u6C60\u7B49\u51E0\u79CD</p><p>\u7279\u6743\u6307\u4EE4\u662F\u6307\u5728\u6307\u4EE4\u7CFB\u7EDF\u4E2D\u90A3\u4E9B\u53EA\u80FD\u7531\u64CD\u4F5C\u7CFB\u7EDF\u4F7F\u7528\u7684\u6307\u4EE4\uFF0C\u5982\u8BBE\u7F6E\u7A0B\u5E8F\u72B6\u6001\u5B57\u3001\u542F\u52A8\u67D0\u8BBE\u5907\u3001\u8BBE\u7F6E\u4E2D\u65AD\u5C4F\u853D\u3001\u8BBE\u7F6E\u65F6\u949F\u6307\u4EE4\u3001\u6E05\u5185\u5B58\u6307\u4EE4\u548C\u5EFA\u7ACB\u5B58\u50A8\u4FDD\u62A4\u6307\u4EE4\u7B49\u7B49</p><p>\u5728\u5F15\u5165\u7EBF\u7A0B\u7684\u64CD\u4F5C\u7CFB\u7EDF\u4E2D\uFF0C\u5219\u628A\u7EBF\u7A0B\u4F5C\u4E3A\u8C03\u5EA6\u548C\u5206\u914D\u7684\u57FA\u672C\u5355\u4F4D\uFF0C\u628A\u8FDB\u7A0B\u4F5C\u4E3A\u8D44\u6E90\u62E5\u6709\u7684\u57FA\u672C\u5355\u4F4D</p><p>\u8FDB\u7A0B\u95F4\u91C7\u7528\u4FE1\u7BB1\u65B9\u5F0F\u8FDB\u884C\u901A\u4FE1\u65F6\uFF0C\u8FDB\u7A0B\u8C03\u7528send\u539F\u8BED\u5E94\u63D0\u4F9B\u7684\u53C2\u6570\u6709\u6307\u5B9A\u7684\u4FE1\u7BB1\u540D\u53CA\u4FE1\u4EF6\u540D</p><p>UNIX\u666E\u901A\u6587\u4EF6\u7684\u7269\u7406\u7ED3\u6784\u662F\u4E09\u7EA7\u7D22\u5F15\u7ED3\u6784</p><p>\u5185\u6838\u5C42\u662FUNIX\u64CD\u4F5C\u7CFB\u7EDF\u7BA1\u7406\u548C\u63A7\u5236\u4E2D\u5FC3\uFF0C\u5E38\u9A7B\u5185\u5B58\u3002\u5176\u5177\u6709\u4E24\u65B9\u9762\u7684\u63A5\u53E3\uFF0C\u4E00\u65B9\u9762\u662F\u5185\u6838\u4E0E\u786C\u4EF6\u7684\u63A5\u53E3\uFF0C\u53E6\u4E00\u65B9\u9762\u662F\u5185\u6838\u4E0EShell\u7684\u63A5\u53E3</p><p>\u5F53\u4E00\u4E2A\u7BA1\u7A0B\u8FC7\u7A0B\u53D1\u73B0\u5B83\u65E0\u6CD5\u7EE7\u7EED\u8FD0\u884C\u65F6\uFF0C\u5B83\u4F1A\u5728\u67D0\u4E2A\u6761\u4EF6\u53D8\u91CF\u4E0A\u6267\u884Cwait\u64CD\u4F5C</p>',90),r=[n];function s(c,d){return e(),t("div",null,r)}const l=p(a,[["render",s],["__file","NormalForm.html.vue"]]);export{l as default};
